solution_code:
#include <iostream>

class Rectangle {
private:
    int m_width;
    int m_height;

public:
    Rectangle(int width, int height) {
        m_width  = width;
        m_height = height;
    }

    int area() const { return m_width * m_height; }
};

int main() {
    int w, h;
    std::cin >> w >> h;

    Rectangle r{ w, h };
    std::cout << "Area: " << r.area() << '\n';

    return 0;
}

