class Countdown {
private:
    int m_seconds;

public:
    Countdown(int start) {
        // Bug: adds instead of assigns
        m_seconds = m_seconds + start;
    }

    void tick(int elapsed) { m_seconds -= elapsed; }
    int getSeconds() const { return m_seconds; }
};

int main() {
    int start, elapsed;
    std::cin >> start >> elapsed;

    Countdown c{ start };
    c.tick(elapsed);

    std::cout << "Remaining: " << c.getSeconds() << '\n';
    return 0;
}

solution_code:
#include <iostream>

class Countdown {
private:
    int m_seconds;

public:
    Countdown(int start) {
        m_seconds = start;
    }

    void tick(int elapsed) { m_seconds -= elapsed; }
    int getSeconds() const { return m_seconds; }
};

int main() {
    int start, elapsed;
    std::cin >> start >> elapsed;

    Countdown c{ start };
    c.tick(elapsed);

    std::cout << "Remaining: " << c.getSeconds() << '\n';
    return 0;
}
